const routes = new Map(); export function registerRoute(path, renderer) { routes.set(path, renderer); } export function getRoute() { const hash = window.location.hash || "#/"; const clean = hash.replace("#", "") || "/"; return clean; } export function navigate(path) { window.location.hash = path; } export function startRouter(renderFallback) { function handleRoute() { const path = getRoute(); const exactRenderer = routes.get(path); if (exactRenderer) { exactRenderer(); updateActiveNav(path); return; } const productMatch = path.match(/^\/products\/([a-z0-9-]+)$/i); if (productMatch && routes.has("/products/:id")) { routes.get("/products/:id")(productMatch[1]); updateActiveNav("/products"); return; } renderFallback(); updateActiveNav(""); } window.addEventListener("hashchange", handleRoute); handleRoute(); } function updateActiveNav(path) { document.querySelectorAll("[data-link]").forEach((link) => { const href = link.getAttribute("href")?.replace("#", "") || ""; const isCurrent = href === path || (path.startsWith("/products") && href === "/products"); if (isCurrent) { link.setAttribute("aria-current", "page"); } else { link.removeAttribute("aria-current"); } }); }
